-- 1. 建立資料表 (如果尚未建立)
CREATE TABLE IF NOT EXISTS Skill (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    nameZh TEXT,
    description TEXT,
    descriptionZh TEXT,
    author TEXT,
    category TEXT,
    tags TEXT, -- 儲存為 JSON 字串
    downloadCount INTEGER DEFAULT 0,
    createdAt TEXT,
    version TEXT,
    githubUrl TEXT,
    folderName TEXT
);

